"use client";

import { useEffect, useState, useRef } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import {
  Search,
  ShoppingBag,
  User,
  Heart,
  Menu,
  Store,
  ChevronDown,
  MessageCircle,
} from "lucide-react";

export default function Navbar() {
  const router = useRouter();
  const pathname = usePathname();

  const profileDropdownRef = useRef(null);
  const categoryPreviewTimeoutRef = useRef(null);

  const [searchQuery, setSearchQuery] = useState("");
  const [categories, setCategories] = useState([]);
  const [customer, setCustomer] = useState(null);
  const [cartCount, setCartCount] = useState(0);
  const [profileDropdownOpen, setProfileDropdownOpen] = useState(false);
  const [userModalOpen, setUserModalOpen] = useState(false);
  const [allMenuOpen, setAllMenuOpen] = useState(false);
  const [activeCategoryId, setActiveCategoryId] = useState(null);
  const [previewCategoryId, setPreviewCategoryId] = useState(null);
  const [searchCategory, setSearchCategory] = useState("All");
  const [whatsappOtpLoading, setWhatsappOtpLoading] = useState(false);

  const isActive = (path) => pathname === path;

  const handleSearchSubmit = (event) => {
    event.preventDefault();

    if (!searchQuery.trim()) return;

    router.push(`/shop?search=${encodeURIComponent(searchQuery.trim())}`);
  };

  const handleLogout = () => {
    localStorage.removeItem("customer");
    localStorage.removeItem("customerData");
    localStorage.removeItem("user");
    localStorage.removeItem("token");

    setCustomer(null);
    setProfileDropdownOpen(false);
    router.push("/");
  };

  const openVendorModal = () => {
    router.push("/vendor-register");
  };

  const sendOtp = () => {
    alert("WhatsApp OTP function yaha connect karna hai");
  };

  const handleCategoryPreview = (categoryId) => {
    clearTimeout(categoryPreviewTimeoutRef.current);
    setPreviewCategoryId(categoryId);
  };

  const clearCategoryPreview = () => {
    categoryPreviewTimeoutRef.current = setTimeout(() => {
      setPreviewCategoryId(null);
    }, 200);
  };

  return (
    <>
      <header
        className="grain sticky top-0 z-50 backdrop-blur-xl border-b border-white/10 overflow-visible relative"
        style={{ backgroundColor: "#131921" }}
      >
        <div className="max-w-[1450px] mx-auto px-3 sm:px-4">
          <div className="h-[64px] min-h-[64px] sm:h-[70px] sm:min-h-[70px] grid grid-cols-[auto_minmax(0,1fr)_auto] items-center gap-3">
            <Link href="/" className="font-black text-xl text-[#FF9900] tracking-tight">
              Jajot
            </Link>

            <div className="hidden md:flex min-w-0 justify-center px-4">
              <form
                onSubmit={handleSearchSubmit}
                className="flex h-10 w-full max-w-[560px] overflow-hidden rounded-[4px] border-2 border-transparent bg-white shadow-[0_2px_10px_rgba(0,0,0,0.15)] transition-all duration-200 focus-within:border-[#FF9900]"
              >
                <input
                  value={searchQuery}
                  onChange={(event) => setSearchQuery(event.target.value)}
                  placeholder="Search for Products, Brands and More"
                  className="min-w-0 flex-1 bg-white px-4 text-sm font-medium text-gray-900 outline-none placeholder:font-normal placeholder:text-gray-500"
                />

                <button
                  type="submit"
                  className="flex w-11 shrink-0 items-center justify-center bg-white text-[#FF9900] hover:text-[#ca8f07] transition"
                  aria-label="Search"
                >
                  <Search size={18} />
                </button>
              </form>
            </div>

            <div className="flex items-center gap-1.5 sm:gap-3">
              <button
                type="button"
                onClick={() => setAllMenuOpen(true)}
                className="md:hidden w-9 h-9 sm:w-10 sm:h-10 border border-white/10 rounded-xl flex items-center justify-center text-white hover:border-[#FF9900] hover:text-[#FF9900] transition-colors"
              >
                <Menu size={18} />
              </button>

              <div className="relative hidden md:block" ref={profileDropdownRef}>
                <button
                  type="button"
                  onClick={() =>
                    customer
                      ? setProfileDropdownOpen((prev) => !prev)
                      : setUserModalOpen(true)
                  }
                  className="flex items-center gap-1.5 px-4 h-9 rounded-md bg-white text-[13px] font-bold text-[#131921] hover:bg-gray-100 transition-colors"
                >
                  <User size={15} className="text-[#FF9900]" />
                  {customer ? customer.name?.split(" ")[0] || "Account" : "Login"}

                  {customer && (
                    <ChevronDown
                      size={13}
                      className={`transition-transform ${
                        profileDropdownOpen ? "rotate-180" : ""
                      }`}
                    />
                  )}
                </button>

                {customer && profileDropdownOpen && (
                  <div className="absolute right-0 top-full mt-2 w-60 bg-white rounded-xl shadow-2xl border border-gray-100 z-[9999] overflow-hidden">
                    <div className="px-4 py-3 border-b border-gray-100">
                      <p className="font-bold text-gray-900 text-sm">
                        Hello {customer.name || "there"}
                      </p>

                      {customer.number && (
                        <p className="text-xs text-gray-500 mt-0.5">
                          {customer.number}
                        </p>
                      )}
                    </div>

                    <div className="py-1">
                      <Link
                        href="/orders"
                        onClick={() => setProfileDropdownOpen(false)}
                        className="block px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900] transition-colors"
                      >
                        Orders
                      </Link>

                      <Link
                        href="/Wishlist"
                        onClick={() => setProfileDropdownOpen(false)}
                        className="block px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900] transition-colors"
                      >
                        Wishlist
                      </Link>

                      <button
                        type="button"
                        onClick={handleLogout}
                        className="w-full text-left px-4 py-2.5 text-sm text-red-600 hover:bg-red-50 transition-colors"
                      >
                        Logout
                      </button>
                    </div>
                  </div>
                )}
              </div>

              <div className="relative hidden md:block group">
                <button
                  type="button"
                  className="flex items-center gap-1.5 px-3 h-9 text-[13px] font-semibold text-white hover:text-[#FF9900] transition-colors"
                >
                  More
                  <ChevronDown size={13} className="group-hover:rotate-180 transition-transform" />
                </button>

                <div className="absolute right-0 top-full pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-[9999]">
                  <div className="w-52 bg-white rounded-xl shadow-2xl border border-gray-100 overflow-hidden py-1">
                    <button
                      type="button"
                      onClick={openVendorModal}
                      className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900] transition-colors"
                    >
                      <Store size={16} /> Become a Vendor
                    </button>

                    <button
                      type="button"
                      onClick={sendOtp}
                      disabled={whatsappOtpLoading}
                      className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-emerald-600 transition-colors disabled:opacity-60"
                    >
                      <MessageCircle size={16} /> WhatsApp OTP
                    </button>

                    <Link
                      href="/Wishlist"
                      className="w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-[#FF9900] transition-colors"
                    >
                      <Heart size={16} /> Wishlist
                    </Link>
                  </div>
                </div>
              </div>

              <Link
                href="/Addtocard"
                className="relative flex items-center gap-1.5 px-3 sm:px-4 h-9 sm:h-10 rounded-md text-white hover:text-[#FF9900] transition-colors font-semibold text-sm"
              >
                <ShoppingBag size={18} />
                <span className="hidden sm:inline">Cart</span>

                {cartCount > 0 && (
                  <span className="absolute -top-1 -right-1 sm:right-0 w-4 h-4 rounded-full bg-[#FF9900] text-black text-[10px] font-bold flex items-center justify-center">
                    {cartCount}
                  </span>
                )}
              </Link>
            </div>
          </div>
        </div>
      </header>

      {userModalOpen && (
        <div className="fixed inset-0 z-[99999] bg-black/50 flex items-center justify-center px-4">
          <div className="bg-white rounded-xl w-full max-w-md p-5 relative">
            <button
              type="button"
              onClick={() => setUserModalOpen(false)}
              className="absolute right-4 top-4 text-gray-500 hover:text-black"
            >
              ✕
            </button>

            <h2 className="text-xl font-bold text-gray-900 mb-2">Login</h2>
            <p className="text-sm text-gray-500">
              Login form yaha paste karna hai.
            </p>
          </div>
        </div>
      )}
    </>
  );
}